(async()=>{
let k='key',l=localStorage,p=l.getItem(k);
if(!p){p=prompt('输入密钥');l.setItem(k,p);}
const payload = {"salt":"2TXTM3Prdk9uKGsVLpLIRA==","iv":"8u+hrhpeQWjTXC3F","data":""};
const s2b = s => Uint8Array.from(atob(s), c => c.charCodeAt(0));
const salt = s2b(payload.salt);
const iv = s2b(payload.iv);
const data = new Uint8Array(await (await fetch('data:application/octet-stream;base64,' + payload.data)).arrayBuffer());
const encoder = new TextEncoder();
const pwKey = await crypto.subtle.importKey('raw', encoder.encode(p), 'PBKDF2', false, ['deriveKey']);
const key = await crypto.subtle.deriveKey(
	{ name: 'PBKDF2', salt: salt, iterations: 10000, hash: 'SHA-256' },
	pwKey,
	{ name: 'AES-GCM', length: 256 },
	false,
	['decrypt']
);
const decrypted = await crypto.subtle.decrypt(
	{ name: 'AES-GCM', iv: iv },
	key,
	data
);
let decodedCode = new TextDecoder().decode(decrypted);
const scriptUrl = window.location.origin + window.location.pathname.replace(/\/[^\/]*$/, '/') + 'index.js';
decodedCode = decodedCode.replace(/import\.meta\.url/g, JSON.stringify(scriptUrl));
decodedCode += "\nsetTimeout(() => { window.dispatchEvent(new Event('DOMContentLoaded')); window.dispatchEvent(new Event('load')); }, 100);";
const s = document.createElement('script');
s.type = 'module';
s.textContent = decodedCode;
document.body.appendChild(s);
})()